import SwiftUI
import SwiftData

struct PersonNetworkView: View {
    @Environment(\.modelContext) private var modelContext
    let focalPerson: Person
    @Query(filter: #Predicate<person> { !$0.isArchived }, sort: \Person.name) private var allPersons: [Person]
    @State private var connectedNodes: [NetworkNode] = []
    @State private var edges: [NetworkEdge] = []
    @State private var showInterSatelliteEdges = false
    enum SortMode: String, CaseIterable { case byStrength = "关联最多"; case byRecency = "最近互动" }
    @State private var sortMode: SortMode = .byStrength
    @State private var roleFilter: PersonRoleType? = nil
    private var displayNodes: [NetworkNode] { guard let filter = roleFilter else { return connectedNodes }; return connectedNodes.filter { $0.roleTypes.contains(filter) } }
    @State private var showPotentialConnections = false
    @State private var potentialNodes: [NetworkNode] = []
    @State private var potentialEdges: [NetworkEdge] = []
    @State private var viewportOffset: CGSize = .zero
    @State private var viewportScale: CGFloat = 1.0
    @State private var lastViewportScale: CGFloat = 1.0
    @GestureState private var dragOffset: CGSize = .zero
    @State private var navigateToPersonID: PersistentIdentifier?
    private let centerNodeRadius: CGFloat = 44
    private let satelliteNodeRadius: CGFloat = 32
    private let ringRadius: CGFloat = 170
    private let potentialRingOffset: CGFloat = 85
    private let minScale: CGFloat = 0.3
    private let maxScale: CGFloat = 2.0
    private let saturationThreshold: Int = 12
    var body: some View {
        GeometryReader { geometry in let canvasSize = geometry.size; ZStack { Color.surfaceLight.ignoresSafeArea(); if connectedNodes.isEmpty { growingNetworkView(in: canvasSize) } else { networkCanvas(in: canvasSize) } }
            .gesture(combinedGesture)
            .overlay(alignment: .top) { if !connectedNodes.isEmpty { VStack(spacing: Spacing.xs) { activityFilterBar; roleFilterBar }.padding(.top, Spacing.sm) } }
            .overlay(alignment: .bottom) { if !connectedNodes.isEmpty { VStack(spacing: Spacing.sm) { expansionToggle; potentialToggle }.padding(.bottom, Spacing.xs) } }
            .onAppear { buildNetwork() }.onChange(of: allPersons) { _, _ in buildNetwork() }.onChange(of: sortMode) { _, _ in sortNodes() }
            .navigationDestination(isPresented: Binding(get: { navigateToPersonID != nil }, set: { if !$0 { navigateToPersonID = nil } })) { if let id = navigateToPersonID, let person = allPersons.first(where: { $0.persistentModelID == id }) { PersonConnectionView(personA: focalPerson, personB: person) } }
        }.navigationTitle("人脉网络").navigationBarTitleDisplayMode(.inline)
    }
    private func sortNodes() { switch sortMode { case .byStrength: connectedNodes.sort { ($0.sharedCaseCount + $0.sharedEventCount) > ($1.sharedCaseCount + $1.sharedEventCount) }; case .byRecency: connectedNodes.sort { nodeA, nodeB in let dateA = latestInteractionDate(for: nodeA) ?? .distantPast; let dateB = latestInteractionDate(for: nodeB) ?? .distantPast; return dateA > dateB } } }
    private func latestInteractionDate(for node: NetworkNode) -> Date? { guard let person = allPersons.first(where: { $0.persistentModelID == node.personID }) else { return nil }; return focalPerson.latestInteractionDate(with: person) }
    private var activityFilterBar: some View { HStack(spacing: 0) { ForEach(SortMode.allCases, id: \.self) { mode in Button { withAnimation(.easeInOut(duration: 0.3)) { sortMode = mode } } label: { Text(mode.rawValue).font(.cnCaption1).foregroundColor(sortMode == mode ? .white : .textSecondary).padding(.horizontal, Spacing.md).padding(.vertical, Spacing.sm).background(Capsule(style: .continuous).fill(sortMode == mode ? Color.tealLink : Color.clear)) } } }.padding(.horizontal, Spacing.sm).padding(.vertical, Spacing.xs).background(Capsule(style: .continuous).fill(Color.surfaceCard.opacity(0.92))).overlay(Capsule(style: .continuous).stroke(Color.divider, lineWidth: 1)).shadow(color: .black.opacity(0.04), radius: 4, x: 0, y: 2).padding(.top, Spacing.sm) }
    private var roleFilterBar: some View { ScrollView(.horizontal, showsIndicators: false) { HStack(spacing: Spacing.xs) { roleFilterChip(label: "全部", isSelected: roleFilter == nil) { withAnimation(.easeInOut(duration: 0.3)) { roleFilter = nil } }; ForEach(PersonRoleType.allCases.filter { $0 != .other }, id: \.self) { role in roleFilterChip(label: role.rawValue, isSelected: roleFilter == role) { withAnimation(.easeInOut(duration: 0.3)) { roleFilter = (roleFilter == role) ? nil : role } } } }.padding(.horizontal, Spacing.sm) } }
    private func roleFilterChip(label: String, isSelected: Bool, action: @escaping () -> Void) -> some View { Button(action: action) { Text(label).font(.cnCaption2).foregroundColor(isSelected ? .white : .textSecondary).padding(.horizontal, Spacing.sm).padding(.vertical, 4).background(Capsule(style: .continuous).fill(isSelected ? Color.tealLink : Color.surfaceCard.opacity(0.92))) } }
    private var expansionToggle: some View { Button { withAnimation(.easeInOut(duration: 0.4)) { showInterSatelliteEdges.toggle() } } label: { HStack(spacing: 6) { Image(systemName: showInterSatelliteEdges ? "circle.hexagongrid.fill" : "circle.dotted.circle").font(.system(size: 12, weight: .medium)); Text(showInterSatelliteEdges ? "完整网络" : "核心圈").font(.cnCaption1); if edges.count > 0 { Text("\(edges.count)条关联").font(.cnCaption2).foregroundColor(.textTertiary) } }.foregroundColor(showInterSatelliteEdges ? .tealLink : .textSecondary).padding(.horizontal, Spacing.md).padding(.vertical, Spacing.sm).background(Capsule(style: .continuous).fill(showInterSatelliteEdges ? Color.tealLink.opacity(0.12) : Color.surfaceCard)).overlay(Capsule(style: .continuous).stroke(showInterSatelliteEdges ? Color.tealLink.opacity(0.3) : Color.divider, lineWidth: 1)).shadow(color: .black.opacity(0.04), radius: 4, x: 0, y: 2) } }
    private var potentialToggle: some View { Button { withAnimation(.easeInOut(duration: 0.4)) { showPotentialConnections.toggle() } } label: { HStack(spacing: 6) { Image(systemName: showPotentialConnections ? "eye.fill" : "eye").font(.system(size: 12, weight: .medium)); Text("潜在连接").font(.cnCaption1); if potentialNodes.count > 0 { Text("\(potentialNodes.count)").font(.cnCaption2).foregroundColor(.textTertiary) } }.foregroundColor(showPotentialConnections ? .tealLink : .textSecondary).padding(.horizontal, Spacing.md).padding(.vertical, Spacing.sm).background(Capsule(style: .continuous).fill(showPotentialConnections ? Color.tealLink.opacity(0.12) : Color.surfaceCard)).overlay(Capsule(style: .continuous).stroke(showPotentialConnections ? Color.tealLink.opacity(0.3) : Color.divider, lineWidth: 1)).shadow(color: .black.opacity(0.04), radius: 4, x: 0, y: 2) }.padding(.bottom, Spacing.base) }
    private func networkCanvas(in size: CGSize) -> some View { let center = CGPoint(x: size.width / 2 + viewportOffset.width + dragOffset.width, y: size.height / 2 + viewportOffset.height + dragOffset.height); return ZStack { if showPotentialConnections { ForEach(potentialEdges) { edge in if let from = position(for: edge.fromID, center: center), let to = position(for: edge.toID, center: center) { potentialConnectionLine(from: from, to: to) } } }; if showInterSatelliteEdges { ForEach(edges) { edge in if let from = position(for: edge.fromID, center: center), let to = position(for: edge.toID, center: center) { connectionLine(from: from, to: to, edge: edge) } } }; if showPotentialConnections { ForEach(potentialNodes) { node in if let pos = position(for: node.id, center: center) { potentialNodeView(node, at: pos) } } }; ForEach(displayNodes) { node in if let pos = position(for: node.id, center: center) { satelliteNodeView(node, at: pos) } }; focalNodeView(at: center) }.scaleEffect(viewportScale, anchor: .center) }
    private func connectionLine(from: CGPoint, to: CGPoint, edge: NetworkEdge) -> some View { let frequencyContribution = CGFloat(edge.interactionFrequency) * 0.25; let effective = max(CGFloat(edge.strength) + frequencyContribution, 1); let opacity = min(0.12 + (effective - 1) * 0.06, 0.35); let lineWidth: CGFloat = 0.3 + effective * 0.25; return Path { path in path.move(to: from); let mid = CGPoint(x: (from.x + to.x) / 2, y: (from.y + to.y) / 2 - min(abs(from.y - to.y) * 0.08, 20)); path.addQuadCurve(to: to, control: mid) }.stroke(Color.tealLink.opacity(opacity), style: StrokeStyle(lineWidth: lineWidth, lineCap: .round)) }
    private func potentialConnectionLine(from: CGPoint, to: CGPoint) -> some View { Path { path in path.move(to: from); path.addLine(to: to) }.stroke(Color.textTertiary.opacity(0.15), style: StrokeStyle(lineWidth: 0.5, dash: [5, 8], lineCap: .round)) }
    private func focalNodeView(at position: CGPoint) -> some View { let primaryRole = focalPerson.roleTypes.first ?? .other; let roleColor = primaryRole.swiftUIColor; return VStack(spacing: 4) { AvatarPlaceholder(roleType: primaryRole, size: centerNodeRadius * 2).overlay(Circle().stroke(roleColor, lineWidth: 2.5)).shadow(color: roleColor.opacity(0.18), radius: 14, x: 0, y: 4); Text(focalPerson.name).font(.cnHeadline).foregroundColor(.textPrimary).lineLimit(1).fixedSize(); RoleTypeTag(roleType: primaryRole).scaleEffect(0.85); if let signal = focalPerson.activitySignal { ActivitySignalView(signal: signal).scaleEffect(0.8) } }.position(position).accessibilityElement(children: .combine).accessibilityLabel("中心：\(focalPerson.name)").accessibilityAddTraits(.isHeader) }
    private func satelliteNodeView(_ node: NetworkNode, at position: CGPoint) -> some View { let primaryRole = node.roleTypes.first ?? .other; let roleColor = primaryRole.swiftUIColor; let totalConnections = node.sharedCaseCount + node.sharedEventCount; let isDormant: Bool = { if let signal = node.activitySignal, case .inactive = signal { return true }; return false }(); let isThin: Bool = !isDormant && totalConnections == 1; let nodeOpacity: CGFloat = isDormant ? 0.45 : (isThin ? 0.65 : 1.0); let nodeScale: CGFloat = isDormant ? 0.85 : (isThin ? 0.92 : 1.0); return Button { navigateToPersonID = node.personID } label: { VStack(spacing: 3) { AvatarPlaceholder(roleType: primaryRole, size: satelliteNodeRadius * 2).opacity(nodeOpacity).overlay(Circle().stroke(roleColor.opacity(isDormant ? 0.12 : (isThin ? 0.18 : 0.3)), lineWidth: isThin ? 1.0 : 1.5)); Text(node.name).font(.cnCaption1).foregroundColor(.textPrimary).opacity(nodeOpacity).lineLimit(1); if isDormant { Text("休眠").font(.system(size: 9, weight: .medium)).foregroundColor(.textTertiary.opacity(0.6)).padding(.horizontal, 4).padding(.vertical, 1).background(Color.textTertiary.opacity(0.08)).clipShape(RoundedRectangle(cornerRadius: 3)) } else if isThin { Text("1个连接").font(.cnCaption2).foregroundColor(.textTertiary) } else { Text("\(totalConnections)个连接").font(.cnCaption2).foregroundColor(.textTertiary) }; if let signal = node.activitySignal { ActivitySignalView(signal: signal).scaleEffect(0.7).opacity(nodeOpacity) } } }.buttonStyle(.plain).position(position).scaleEffect(nodeScale).accessibilityElement(children: .combine).accessibilityLabel("\(node.name)，\(totalConnections)个连接").accessibilityHint("轻点以查看你们之间的连接详情") }
    private func potentialNodeView(_ node: NetworkNode, at position: CGPoint) -> some View { let primaryRole = node.roleTypes.first ?? .other; let roleColor = primaryRole.swiftUIColor; let size = satelliteNodeRadius * 1.8; return Button { navigateToPersonID = node.personID } label: { VStack(spacing: 2) { AvatarPlaceholder(roleType: primaryRole, size: size).opacity(0.5).overlay(Circle().stroke(roleColor.opacity(0.18), style: StrokeStyle(lineWidth: 1, dash: [3, 3])).frame(width: size, height: size)); Text(node.name).font(.cnCaption2).foregroundColor(.textTertiary).lineLimit(1); Text("潜在").font(.system(size: 9, weight: .medium)).foregroundColor(.textTertiary.opacity(0.7)).padding(.horizontal, 4).padding(.vertical, 1).background(Color.textTertiary.opacity(0.08)).clipShape(RoundedRectangle(cornerRadius: 3)) } }.buttonStyle(.plain).position(position).accessibilityElement(children: .combine).accessibilityLabel("\(node.name)，潜在连接") }
    private func growingNetworkView(in size: CGSize) -> some View { VStack(spacing: Spacing.xl) { Spacer(); ZStack { Circle().stroke(Color.tealLink.opacity(0.08), lineWidth: 1).frame(width: 220, height: 220); Circle().stroke(Color.tealLink.opacity(0.15), lineWidth: 1.5).frame(width: 140, height: 140); if let primaryRole = focalPerson.roleTypes.first { AvatarPlaceholder(roleType: primaryRole, size: 60).shadow(color: Color.tealLink.opacity(0.10), radius: 8, x: 0, y: 2) } }; VStack(spacing: Spacing.sm) { Text("你的网络正在生长").font(.cnTitle3).foregroundColor(.textPrimary); let othersCount = allPersons.filter { $0.persistentModelID != focalPerson.persistentModelID }.count; if othersCount == 0 { Text("还没有其他联系人。
添加第一位人脉，从这里开始编织你的网络。").font(.cnBody).foregroundColor(.textSecondary).multilineTextAlignment(.center).lineSpacing(4) } else if othersCount > 0 { Text("目前没有与其他人共同参与的案件或事件。
当你们一起协作，这里就会亮起来。").font(.cnBody).foregroundColor(.textSecondary).multilineTextAlignment(.center).lineSpacing(4) } }.padding(.horizontal, Spacing.xxl); Spacer() }.frame(maxWidth: .infinity, maxHeight: .infinity) }
    private var combinedGesture: some Gesture { SimultaneousGesture(DragGesture().updating($dragOffset) { value, state, _ in state = value.translation }.onEnded { value in viewportOffset.width += value.translation.width; viewportOffset.height += value.translation.height }, MagnificationGesture().onChanged { scale in let newScale = lastViewportScale * scale; viewportScale = min(max(newScale, minScale), maxScale) }.onEnded { _ in lastViewportScale = viewportScale }) }
    private func position(for nodeID: String, center: CGPoint) -> CGPoint? { if nodeID == "focal" { return center }; if let index = displayNodes.firstIndex(where: { $0.id == nodeID }) { return ringPosition(index: index, total: displayNodes.count, center: center) }; if let index = potentialNodes.firstIndex(where: { $0.id == nodeID }) { return ringPosition(index: index, total: potentialNodes.count, center: center, radiusOffset: potentialRingOffset) }; return nil }
    private func ringPosition(index: Int, total: Int, center: CGPoint, radiusOffset: CGFloat = 0) -> CGPoint { guard total > 0 else { return center }; let angle: Double; if total <= saturationThreshold { angle = (2 * .pi / Double(total)) * Double(index) - .pi / 2 } else { let halfCount = Int(ceil(Double(total) / 2.0)); let isOuter = index >= halfCount; let localIndex = isOuter ? index - halfCount : index; let localCount = isOuter ? total - halfCount : halfCount; let localAngle = (2 * .pi / Double(localCount)) * Double(localIndex) - .pi / 2; let offsetAngle = isOuter ? (.pi / Double(localCount)) : 0; angle = localAngle + offsetAngle }; let ringIndex = total > saturationThreshold && index >= Int(ceil(Double(total) / 2.0)) ? 1 : 0; let radius = ringRadius + CGFloat(ringIndex) * 70 + radiusOffset; return CGPoint(x: center.x + CGFloat(cos(angle)) * radius, y: center.y + CGFloat(sin(angle)) * radius) }
    private func buildNetwork() { let others = allPersons.filter { $0.persistentModelID != focalPerson.persistentModelID }; var nodes: [NetworkNode] = []; var personIDToNodeIndex: [PersistentIdentifier: Int] = [:]; for person in others { let sharedCases = focalPerson.sharedCases(with: person); let sharedEvents = focalPerson.sharedEvents(with: person); let total = sharedCases.count + sharedEvents.count; if total > 0 { let signal = person.activitySignal; let node = NetworkNode(id: "n\(nodes.count)", personID: person.persistentModelID, name: person.name, roleTypes: person.roleTypes, sharedCaseCount: sharedCases.count, sharedEventCount: sharedEvents.count, activitySignal: signal); personIDToNodeIndex[person.persistentModelID] = nodes.count; nodes.append(node) } }; nodes.sort { ($0.sharedCaseCount + $0.sharedEventCount) > ($1.sharedCaseCount + $1.sharedEventCount) }; var computedEdges: [NetworkEdge] = []; var edgeSet: Set<string> = []; for i in 0..<nodes.count {="" for="" j="" in="" (i="" +="" 1)..<nodes.count="" guard="" let="" persona="allPersons.first(where:" $0.persistentmodelid="=" nodes[i].personid="" }),="" personb="allPersons.first(where:" nodes[j].personid="" })="" else="" continue="" };="" sharedcount="personA.sharedCases(with:" personb).count="" persona.sharedevents(with:="" personb).count;=""> 0 else { continue }; let freq = personA.interactionFrequency(with: personB); let edgeKey = "e\(nodes[i].id)-\(nodes[j].id)"; if !edgeSet.contains(edgeKey) { edgeSet.insert(edgeKey); computedEdges.append(NetworkEdge(id: edgeKey, fromID: nodes[i].id, toID: nodes[j].id, strength: sharedCount, interactionFrequency: freq)) } } }; let connectedPersonIDs = Set(nodes.map { $0.personID }); var potNodes: [NetworkNode] = []; var potEdges: [NetworkEdge] = []; let focalCaseTypes = Set(focalPerson.cases.map { $0.caseType }); let focalOrg = focalPerson.org; for person in others { guard !connectedPersonIDs.contains(person.persistentModelID) else { continue }; let sameOrg = focalOrg != nil && person.org == focalOrg; let personCaseTypes = Set(person.cases.map { $0.caseType }); let sameCaseType = !focalCaseTypes.intersection(personCaseTypes).isEmpty; var depthTwoCount = 0; for node in nodes { if let connectedPerson = allPersons.first(where: { $0.persistentModelID == node.personID }) { depthTwoCount += connectedPerson.sharedCases(with: person).count } }; let isPotential = sameOrg || sameCaseType || depthTwoCount > 0; guard isPotential else { continue }; let directShared = focalPerson.sharedCases(with: person).count + focalPerson.sharedEvents(with: person).count; guard directShared == 0 else { continue }; let signal = person.activitySignal; let potNode = NetworkNode(id: "p\(potNodes.count)", personID: person.persistentModelID, name: person.name, roleTypes: person.roleTypes, sharedCaseCount: 0, sharedEventCount: 0, activitySignal: signal); potNodes.append(potNode) }; var potEdgeSet: Set<string> = []; for potNode in potNodes { guard let potPerson = allPersons.first(where: { $0.persistentModelID == potNode.personID }) else { continue }; for node in nodes { guard let connectedPerson = allPersons.first(where: { $0.persistentModelID == node.personID }) else { continue }; let indirectCount = connectedPerson.sharedCases(with: potPerson).count + connectedPerson.sharedEvents(with: potPerson).count; if indirectCount > 0 { let freq = connectedPerson.interactionFrequency(with: potPerson); let edgeKey = "pe-\(node.id)-\(potNode.id)"; if !potEdgeSet.contains(edgeKey) { potEdgeSet.insert(edgeKey); potEdges.append(NetworkEdge(id: edgeKey, fromID: node.id, toID: potNode.id, strength: indirectCount, interactionFrequency: freq)) } } } }; withAnimation(.easeInOut(duration: 0.5)) { connectedNodes = nodes; edges = computedEdges; potentialNodes = potNodes; potentialEdges = potEdges } }
}
private struct NetworkNode: Identifiable { let id: String; let personID: PersistentIdentifier; let name: String; let roleTypes: [PersonRoleType]; let sharedCaseCount: Int; let sharedEventCount: Int; let activitySignal: ActivitySignal? }
private struct NetworkEdge: Identifiable { let id: String; let fromID: String; let toID: String; let strength: Int; let interactionFrequency: Int }